/**
 * generate-weekly-backfill.js
 *
 * Fetches specific GitHub Releases by tag name, aggregates their content,
 * sends to Claude API with the weekly marketing prompt, posts to Slack,
 * and creates a GitHub Release for the given week-ending date.
 *
 * Environment variables required:
 *   GITHUB_TOKEN            - GitHub token (provided by Actions)
 *   GITHUB_REPOSITORY       - "owner/repo" (provided by Actions)
 *   ANTHROPIC_API_KEY       - Claude API key
 *   SLACK_WEBHOOK_RELEASES  - Slack incoming webhook URL
 *   WEEK_ENDING             - Week ending date in DD-MM-YYYY format
 *   DAILY_TAGS              - Space-separated list of daily release tags
 */

import { Octokit } from '@octokit/rest';
import { IncomingWebhook } from '@slack/webhook';
import Anthropic from '@anthropic-ai/sdk';
import { readFileSync } from 'fs';
import { join, dirname } from 'path';
import { fileURLToPath } from 'url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const [owner, repo] = process.env.GITHUB_REPOSITORY.split('/');
const octokit = new Octokit({ auth: process.env.GITHUB_TOKEN });

const weekEnding = process.env.WEEK_ENDING;
const dailyTags = process.env.DAILY_TAGS.trim().split(/\s+/);

console.log(`Backfilling weekly summary for week ending ${weekEnding}`);
console.log(`Daily tags: ${dailyTags.join(', ')}`);

async function main() {
  // Fetch each specified daily release
  const releases = [];
  for (const tag of dailyTags) {
    try {
      const { data } = await octokit.repos.getReleaseByTag({ owner, repo, tag });
      releases.push(data);
      console.log(`Fetched release: ${tag}`);
    } catch (err) {
      console.warn(`Could not fetch release ${tag}: ${err.message}`);
    }
  }

  if (releases.length === 0) {
    console.log('No releases found. Aborting.');
    process.exit(1);
  }

  const aggregated = releases
    .sort((a, b) => a.tag_name.localeCompare(b.tag_name))
    .map(r => `## ${r.name}\n\n${r.body}`)
    .join('\n\n---\n\n');

  // Load prompt
  const promptPath = join(__dirname, '../../prompts/weekly-marketing.md');
  const systemPrompt = readFileSync(promptPath, 'utf-8');

  let summary;
  if (!process.env.ANTHROPIC_API_KEY) {
    console.warn('ANTHROPIC_API_KEY not set — using raw aggregated notes as summary');
    summary = aggregated;
  } else {
    console.log('Calling Claude API for weekly summary...');
    const client = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
    const message = await client.messages.create({
      model: 'claude-sonnet-4-6',
      max_tokens: 1024,
      system: systemPrompt,
      messages: [{ role: 'user', content: `Week ending ${weekEnding}\n\nDaily release notes:\n\n${aggregated}` }],
    });
    summary = message.content[0].text;
    console.log('Weekly summary:\n', summary);
  }

  // Convert to Slack mrkdwn: **bold** → *bold*, prefix each heading line with • and indent description
  const slackBody = summary
    .replace(/\*\*([^*\n]+)\*\*/g, '*$1*')
    .replace(/^(\*[^*\n]+\*)\n/gm, '• $1\n  ')
    .trim();

  // Post to Slack
  if (process.env.SLACK_WEBHOOK_RELEASES) {
    const webhook = new IncomingWebhook(process.env.SLACK_WEBHOOK_RELEASES);
    await webhook.send({
      blocks: [
        {
          type: 'header',
          text: { type: 'plain_text', text: `Weekly Product Update — ${weekEnding}` },
        },
        {
          type: 'section',
          text: { type: 'mrkdwn', text: slackBody },
        },
        {
          type: 'context',
          elements: [
            { type: 'mrkdwn', text: `Based on ${releases.length} daily release${releases.length !== 1 ? 's' : ''} | Generated by Claude` },
          ],
        },
      ],
    });
    console.log('Posted weekly summary to Slack');
  } else {
    console.warn('SLACK_WEBHOOK_RELEASES not set — skipping Slack');
  }

  // Publish as a GitHub Release
  const tagName = `weekly-${weekEnding}`;
  const headSha = (await octokit.repos.getBranch({ owner, repo, branch: 'main' })).data.commit.sha;

  await octokit.git.createRef({ owner, repo, ref: `refs/tags/${tagName}`, sha: headSha })
    .catch(async (err) => {
      if (err.status === 422) {
        await octokit.git.updateRef({ owner, repo, ref: `tags/${tagName}`, sha: headSha, force: true });
      } else throw err;
    });

  const existingReleases = await octokit.repos.listReleases({ owner, repo, per_page: 20 });
  const existing = existingReleases.data.find(r => r.tag_name === tagName);
  if (existing) await octokit.repos.deleteRelease({ owner, repo, release_id: existing.id });

  const { data: weeklyRelease } = await octokit.repos.createRelease({
    owner, repo,
    tag_name: tagName,
    name: `Weekly Product Update — ${weekEnding}`,
    body: summary,
    prerelease: false,
  });
  console.log(`Created GitHub Release: ${weeklyRelease.html_url}`);

  console.log(`Backfill complete for week ending ${weekEnding}.`);
}

main().catch(err => {
  console.error(err);
  process.exit(1);
});
